const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let audioOverview;
let fallback = false;

try {
  audioOverview = JSON.parse(cleaned);

  if (!audioOverview.title || !Array.isArray(audioOverview.segments)) {
    throw new Error("Invalid audio overview format");
  }
} catch (error) {
  fallback = true;
  audioOverview = {
    title: "Study Aura Audio Overview",
    description: "A quick fallback audio review for the selected topic.",
    estimatedDuration: "1 minute",
    segments: [
      {
        speaker: "Audio",
        text: "Welcome to this Study Aura audio overview. In this short review, we will focus on the main idea, important details, and a simple way to remember the topic."
      },
      {
        speaker: "Audio",
        text: "Start by identifying the key concept. Then connect it to examples, definitions, and review questions so the idea becomes easier to recall."
      }
    ],
    recap: ["Identify the main idea", "Connect details with examples", "Review using active recall"]
  };
}

const cleanSpeakerLabel = (value) => {
  return String(value || "")
    .replace(/^\s*(Narrator|Host A|Host B|Audio|Speaker)\s*:\s*/i, "")
    .trim();
};

const segments = Array.isArray(audioOverview.segments)
  ? audioOverview.segments.map((segment) => ({
      speaker: "Audio",
      text: cleanSpeakerLabel(segment.text || "Review this topic carefully.")
    })).filter((segment) => segment.text)
  : [];

const recap = Array.isArray(audioOverview.recap)
  ? audioOverview.recap.map((item) => cleanSpeakerLabel(item)).filter(Boolean).slice(0, 5)
  : ["Review the main idea", "Practice recall", "Connect examples"];

const script = segments.map((segment) => segment.text).join("\n\n");

return [
  {
    json: {
      audioOverview: {
        title: String(audioOverview.title || "Study Aura Audio Overview"),
        description: String(audioOverview.description || "Generated audio overview."),
        estimatedDuration: String(audioOverview.estimatedDuration || "2 minutes"),
        segments,
        recap,
        script
      },
      fallback,
      provider: "gemini"
    }
  }
];

const binaryAudio = $binary.premiumAudio;
const audioOverview = $json.audioOverview;

return [
  {
    json: {
      audioOverview: {
        ...audioOverview,
        premiumAudio: {
          provider: "elevenlabs",
          voice: "Premium Narrator",
          mimeType: binaryAudio.mimeType || "audio/mpeg",
          base64: binaryAudio.data
        }
      },
      provider: "elevenlabs",
      scriptProvider: $json.provider || "gemini",
      fallback: false
    }
  }
];

